#include <bits/stdc++.h>
using namespace std;

const int N=2e4+10,M=2e5+10;

int n,m,root;
int head[N],ver[M],nxt[M],tot;
int dfn[N],low[N],num;
bool cut[N];
vector<int> ans;

void add(int u,int v){
    ver[++tot]=v,nxt[tot]=head[u],head[u]=tot;
    ver[++tot]=u,nxt[tot]=head[v],head[v]=tot;
}

void tarjan(int x){
    dfn[x]=low[x]=++num;
    bool flag=0;
    for(int i=head[x],y;i;i=nxt[i])
        if(!dfn[y=ver[i]]){
            tarjan(y);
            low[x]=min(low[x],low[y]);
            if(low[y]>=dfn[x] && (flag || x!=root)){
                if(!cut[x])
                    ans.push_back(x);
                cut[x]=1;
            }
            if(low[y]>=dfn[x])
                flag=1;
        }else
            low[x]=min(low[x],dfn[y]);
}

int main(){
    scanf("%d%d",&n,&m);
    for(int i=1,u,v;i<=m;i++){
        scanf("%d%d",&u,&v);
        add(u,v);
    }
    for(int i=1;i<=n;i++)
        if(!dfn[i]){
            root=i;
            tarjan(i);
        }
    sort(ans.begin(),ans.end());
    printf("%d\n",ans.size());
    for(int i:ans)
        printf("%d ",i);
    return 0;
}
